function inferredType(valueNode: Node): string | null {
  try {
    const t = (valueNode as unknown as { getType?: () => { getText: (n?: Node) => string } }).getType?.();
    if (!t) return null;
    return clamp(t.getText(valueNode));
  } catch {
    return null;
  }
}

