export function buildNamespace(ns: Node, root: string): { sig: string; ns: TSNamespace } {
  const sig = computeSignatureForDecl(ns, root) ?? `${fileKeyOf(ns.getSourceFile().getFilePath(), root).modulePrefix}.(anonymous)`;
