  return {
    sig,
    ns: {
      name: (ns as unknown as { getName: () => string }).getName(),
      signature: sig,
      comments: jsDocsOf(ns),
      ...buckets,
      is_exported: isExportedDecl(ns),
      is_ambient: isAmbientDecl(ns),
      start_line: ns.getStartLineNumber(true),
