function isTestFile(relKey: string): boolean {
  const base = path.basename(relKey);
  if (/\.(test|spec)\.(ts|tsx|mts|cts)$/.test(base)) return true;
  return relKey.split("/").some((p) => TEST_DIRS.has(p));
}

